import ballerina/io;

// Shows pending orders with delivery fees
type Order record {|
    string id;
    string customer;
    int amount;
    string zone;
|};

public function main() {
    Order[] orders = [
        {id: "ORD001", customer: "Alice", amount: 150, zone: "Downtown"},
        {id: "ORD002", customer: "Bob", amount: 75, zone: "Suburb"},
        {id: "ORD003", customer: "Carol", amount: 200, zone: "Downtown"}
    ];
    map<int> deliveryFee = {"Downtown": 5, "Suburb": 10};

    io:println("=== Pending Orders ===");
    foreach int i in 0 ..< orders.length() {
        Order ord = orders[i];
        io:println(i + 1, ". ", ord.id, " | ",
                ord.customer, " | $", ord.amount,
                " | ", ord.zone, " (fee: $", deliveryFee[ord.zone], ")");
    }
}

import ballerina/io;

// Aggregates responses from multiple API endpoints, categorizes them by status
// and flags, and processes mixed result types.
type ApiResponse record {|
    string ep;
    int status;
    int flags;
    any result;
|};

public function main() {
    // Response flags
    int cached = 1 << 0;
    int partial = 1 << 1;
    int paginated = 1 << 2;

    ApiResponse[] responses = [
        {ep: "/users", status: 200, flags: cached, result: 150},
        {ep: "/orders", status: 200, flags: cached + paginated, result: "paginated"},
        {ep: "/products", status: 206, flags: partial, result: 42}
    ];
    [string, int] healthCheck = ["/health", 200];

    io:println("Health Check: ", healthCheck[0], " (", healthCheck[1], ")");

    foreach ApiResponse res in responses {
        io:println("\nEndpoint: ", res.ep, ",\n  Status: ", res.status);

        if res.flags >= paginated {
            io:println("  [Paginated]");
        } else if res.flags == cached {
            io:println("  [Cached]");
        } else {
            io:println("  [Partial]");
        }

        any result = res.result;
        if result is int {
            int count = <int>result;
            io:println("  Count: ", count);
        } else if result is string {
            io:println("  Info: ", result);
        }
    }
}

import ballerina/io;

public function main() {
    int n = 10;
    int i = 0;
    while (i < n) {
        io:println("F(", i, ") = ", fibonacci(i));
        i += 1;
    }
}

function fibonacci(int n) returns int {
    if (n <= 1) {
        return n;
    }
    int prev = 0;
    int curr = 1;
    int i = 2;
    while (i <= n) {
        int next = prev + curr;
        prev = curr;
        curr = next;
        i += 1;
    }
    return curr;
}
